import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

// ─── Theme tokens (matches LandingPage exactly) ────────────────────────────────
const themes = {
  light: {
    bg:           '#F5F0E8',
    bgCard:       '#FFFFFF',
    bgAlt:        '#EDE8DC',
    text:         '#1C1A16',
    textSub:      '#5C5647',
    textMuted:    '#9C9080',
    accent:       '#C17B2A',
    accentLight:  '#F0D9B5',
    accentGlow:   'rgba(193,123,42,0.2)',
    navy:         '#1E3A5F',
    border:       'rgba(28,26,22,0.1)',
    borderStrong: 'rgba(28,26,22,0.18)',
    inputBg:      '#FFFFFF',
    inputBorder:  '#dde3eb',
    shadow:       '0 4px 32px rgba(28,26,22,0.1)',
    shadowLg:     '0 20px 60px rgba(28,26,22,0.12)',
    panelGrad:    'linear-gradient(145deg, #0d2137 0%, #1a3c5e 50%, #1e5080 100%)',
    panelBlob1:   '#e67e22',
    panelBlob2:   '#3498db',
  },
  dark: {
    bg:           '#0F0E0B',
    bgCard:       '#1C1A14',
    bgAlt:        '#161410',
    text:         '#F0EBE0',
    textSub:      '#B8AD9E',
    textMuted:    '#6B6357',
    accent:       '#E09640',
    accentLight:  'rgba(224,150,64,0.15)',
    accentGlow:   'rgba(224,150,64,0.25)',
    navy:         '#4A90D9',
    border:       'rgba(240,235,224,0.08)',
    borderStrong: 'rgba(240,235,224,0.15)',
    inputBg:      '#1C1A14',
    inputBorder:  'rgba(240,235,224,0.12)',
    shadow:       '0 4px 32px rgba(0,0,0,0.4)',
    shadowLg:     '0 20px 60px rgba(0,0,0,0.5)',
    panelGrad:    'linear-gradient(145deg, #060810 0%, #0d1a2e 50%, #0f2040 100%)',
    panelBlob1:   '#c17b2a',
    panelBlob2:   '#1a3c5e',
  },
};

// ─── Dark mode preference stored in localStorage ───────────────────────────────
const getInitialDark = () => {
  try {
    const stored = localStorage.getItem('propmaintain_theme');
    if (stored) return stored === 'dark';
    return window.matchMedia('(prefers-color-scheme: dark)').matches;
  } catch { return false; }
};

const AuthLayout = ({ children, title, subtitle }) => {
  const [dark, setDark] = useState(getInitialDark);
  const t = dark ? themes.dark : themes.light;

  useEffect(() => {
    localStorage.setItem('propmaintain_theme', dark ? 'dark' : 'light');
  }, [dark]);

  const features = [
    { icon: '⚡', text: 'Real-time matching' },
    { icon: '📅', text: 'Smart scheduling'   },
    { icon: '🔒', text: 'Secure & verified'  },
    { icon: '💬', text: 'In-app messaging'   },
  ];

  return (
    <div style={{ display: 'flex', minHeight: '100vh', fontFamily: "'Outfit', sans-serif", background: t.bg, transition: 'background 0.4s, color 0.4s' }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600;700;800;900&family=Playfair+Display:ital,wght@0,700;1,600&display=swap');
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        @keyframes float    { 0%,100%{transform:translateY(0);} 50%{transform:translateY(-10px);} }
        @keyframes rotateSlow { from{transform:rotate(0deg);} to{transform:rotate(360deg);} }
        @keyframes pulse    { 0%,100%{opacity:0.5;transform:scale(1);} 50%{opacity:1;transform:scale(1.08);} }
        @keyframes fadeUp   { from{opacity:0;transform:translateY(20px);} to{opacity:1;transform:translateY(0);} }
        @keyframes spin     { to{transform:rotate(360deg);} }
        .auth-input { transition: border-color 0.2s, box-shadow 0.2s; }
        .auth-input:focus { outline: none !important; border-color: ${t.accent} !important; box-shadow: 0 0 0 3px ${t.accentGlow} !important; }
        .theme-toggle:hover { transform: rotate(20deg) scale(1.1); }
        .feature-pill:hover { background: rgba(255,255,255,0.18) !important; }
        .auth-link:hover { color: ${t.accent} !important; }
      `}</style>

      {/* ── LEFT PANEL ─────────────────────────────────────────────────────── */}
      <div style={{
        flex: '0 0 44%', position: 'relative', overflow: 'hidden',
        background: t.panelGrad,
        display: 'flex', alignItems: 'center', padding: '48px',
      }}>

        {/* Decorative rotating rings */}
        <div style={{ position: 'absolute', top: '10%', right: '-60px', width: '380px', height: '380px', borderRadius: '50%', border: '1px solid rgba(255,255,255,0.07)', animation: 'rotateSlow 30s linear infinite', pointerEvents: 'none' }} />
        <div style={{ position: 'absolute', top: '16%', right: '-20px', width: '260px', height: '260px', borderRadius: '50%', border: '1px dashed rgba(193,123,42,0.25)', animation: 'rotateSlow 20s linear infinite reverse', pointerEvents: 'none' }} />

        {/* Decorative blobs */}
        <div style={{ position: 'absolute', top: '-60px', right: '-60px', width: '320px', height: '320px', borderRadius: '50%', background: t.panelBlob1, filter: 'blur(90px)', opacity: 0.18, pointerEvents: 'none' }} />
        <div style={{ position: 'absolute', bottom: '-40px', left: '-40px', width: '240px', height: '240px', borderRadius: '50%', background: t.panelBlob2, filter: 'blur(70px)', opacity: 0.2, pointerEvents: 'none' }} />

        {/* Floating orb */}
        <div style={{ position: 'absolute', top: '30%', right: '14%', width: '64px', height: '64px', borderRadius: '50%', background: 'radial-gradient(circle, rgba(193,123,42,0.3), transparent)', animation: 'float 6s ease-in-out infinite', pointerEvents: 'none' }} />

        {/* Content */}
        <div style={{ position: 'relative', zIndex: 2, width: '100%' }}>

          {/* Logo */}
          <Link to="/home" style={{ display: 'flex', alignItems: 'center', gap: '10px', textDecoration: 'none', marginBottom: '60px' }}>
            <div style={{ width: '40px', height: '40px', background: `linear-gradient(135deg, ${t.accent}, #1E3A5F)`, borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '20px', boxShadow: `0 4px 16px ${t.accentGlow}` }}>🏠</div>
            <span style={{ fontSize: '22px', fontWeight: '800', color: '#ffffff', letterSpacing: '-0.5px' }}>
              Prop<span style={{ color: t.accent }}>Maintain</span>
            </span>
          </Link>

          {/* Heading */}
          <div style={{ marginBottom: '48px', animation: 'fadeUp 0.7s ease both' }}>
            <div style={{ display: 'inline-flex', alignItems: 'center', gap: '8px', padding: '5px 12px', borderRadius: '20px', background: 'rgba(193,123,42,0.2)', border: '1px solid rgba(193,123,42,0.3)', marginBottom: '20px' }}>
              <span style={{ width: '6px', height: '6px', borderRadius: '50%', background: t.accent, animation: 'pulse 2s infinite', display: 'inline-block' }} />
              <span style={{ fontSize: '11px', fontWeight: '700', color: t.accent, letterSpacing: '1px', textTransform: 'uppercase' }}>Now Live in the UK</span>
            </div>
            <h2 style={{ fontFamily: "'Playfair Display', serif", fontSize: '36px', fontWeight: '700', color: '#ffffff', lineHeight: 1.15, letterSpacing: '-0.5px', marginBottom: '14px' }}>
              Your Home,<br />
              <em style={{ color: t.accent, fontStyle: 'italic' }}>Perfectly</em><br />
              Maintained.
            </h2>
            <p style={{ fontSize: '14px', color: 'rgba(255,255,255,0.65)', lineHeight: 1.7, maxWidth: '320px' }}>
              On-demand property maintenance connecting you with verified professionals — instantly or scheduled.
            </p>
          </div>

          {/* Feature pills */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
            {features.map(({ icon, text }, i) => (
              <div key={text} className="feature-pill" style={{
                display: 'flex', alignItems: 'center', gap: '12px',
                background: 'rgba(255,255,255,0.08)',
                border: '1px solid rgba(255,255,255,0.1)',
                borderRadius: '10px', padding: '11px 16px',
                fontSize: '13px', fontWeight: '500', color: 'rgba(255,255,255,0.85)',
                backdropFilter: 'blur(4px)', cursor: 'default',
                transition: 'background 0.2s',
                animation: `fadeUp 0.6s ease ${0.1 * i}s both`,
              }}>
                <span style={{ fontSize: '18px' }}>{icon}</span>
                {text}
              </div>
            ))}
          </div>

          {/* Social proof */}
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginTop: '36px', animation: 'fadeUp 0.7s ease 0.5s both' }}>
            <div style={{ display: 'flex' }}>
              {['#C17B2A','#1E3A5F','#2A7A4A','#8B4B8B','#C44B4B'].map((c, i) => (
                <div key={i} style={{ width: '28px', height: '28px', borderRadius: '50%', background: c, border: '2px solid rgba(255,255,255,0.2)', marginLeft: i > 0 ? '-7px' : 0, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '10px', fontWeight: '700', color: '#fff' }}>
                  {['S','J','P','A','M'][i]}
                </div>
              ))}
            </div>
            <div>
              <div style={{ fontSize: '12px', fontWeight: '600', color: '#fff' }}>⭐ <span style={{ color: t.accent }}>4.9/5</span></div>
              <div style={{ fontSize: '11px', color: 'rgba(255,255,255,0.5)' }}>2,400+ verified reviews</div>
            </div>
          </div>
        </div>
      </div>

      {/* ── RIGHT PANEL ────────────────────────────────────────────────────── */}
      <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '32px 24px', overflowY: 'auto', position: 'relative' }}>

        {/* Theme toggle — top right */}
        <button
          className="theme-toggle"
          onClick={() => setDark(!dark)}
          style={{
            position: 'absolute', top: '24px', right: '24px',
            width: '40px', height: '40px', borderRadius: '50%',
            border: `1px solid ${t.borderStrong}`,
            background: t.bgCard, cursor: 'pointer',
            fontSize: '18px', display: 'flex', alignItems: 'center', justifyContent: 'center',
            boxShadow: t.shadow, transition: 'all 0.3s',
          }}
          title="Toggle dark/light mode"
        >
          {dark ? '☀️' : '🌙'}
        </button>

        <div style={{ width: '100%', maxWidth: '420px', animation: 'fadeUp 0.6s ease both' }}>

          {/* Form header */}
          {(title || subtitle) && (
            <div style={{ marginBottom: '28px' }}>
              {title && (
                <h1 style={{ fontSize: '28px', fontWeight: '800', color: t.text, margin: '0 0 8px', letterSpacing: '-0.4px', fontFamily: "'Outfit', sans-serif" }}>
                  {title}
                </h1>
              )}
              {subtitle && (
                <p style={{ fontSize: '14px', color: t.textSub, margin: 0, lineHeight: 1.5 }}>
                  {subtitle}
                </p>
              )}
            </div>
          )}

          {/* Inject theme CSS variables for form inputs */}
          <style>{`
            .auth-form-input {
              width: 100%;
              padding: 11px 14px;
              border: 1.5px solid ${t.inputBorder};
              border-radius: 8px;
              font-size: 14px;
              font-family: 'Outfit', sans-serif;
              color: ${t.text};
              background: ${t.inputBg};
              outline: none;
              box-sizing: border-box;
              transition: border-color 0.2s, box-shadow 0.2s;
            }
            .auth-form-input:focus {
              border-color: ${t.accent} !important;
              box-shadow: 0 0 0 3px ${t.accentGlow};
            }
            .auth-form-input::placeholder { color: ${t.textMuted}; }
            .auth-form-label {
              font-size: 13px;
              font-weight: 600;
              color: ${t.text};
              display: block;
              margin-bottom: 6px;
              font-family: 'Outfit', sans-serif;
            }
            .auth-form-error {
              margin: 4px 0 0;
              font-size: 12px;
              color: #e74c3c;
              font-family: 'Outfit', sans-serif;
            }
            .auth-form-hint {
              margin: 4px 0 0;
              font-size: 12px;
              color: ${t.textMuted};
              font-family: 'Outfit', sans-serif;
            }
            .auth-submit-btn {
              width: 100%;
              padding: 13px;
              background: ${t.accent};
              color: #ffffff;
              border: none;
              border-radius: 8px;
              font-size: 15px;
              font-weight: 700;
              font-family: 'Outfit', sans-serif;
              cursor: pointer;
              transition: all 0.25s;
              margin-bottom: 16px;
              box-shadow: 0 4px 16px ${t.accentGlow};
              letter-spacing: 0.2px;
            }
            .auth-submit-btn:hover { transform: translateY(-2px); box-shadow: 0 8px 24px ${t.accentGlow}; }
            .auth-submit-btn:disabled { background: ${t.textMuted}; cursor: not-allowed; transform: none; box-shadow: none; }
            .auth-secondary-btn {
              display: block;
              width: 100%;
              padding: 12px;
              border: 2px solid ${t.borderStrong};
              border-radius: 8px;
              text-align: center;
              font-size: 14px;
              font-weight: 600;
              font-family: 'Outfit', sans-serif;
              color: ${t.text};
              text-decoration: none;
              transition: all 0.2s;
              background: transparent;
              box-sizing: border-box;
            }
            .auth-secondary-btn:hover { background: ${t.border}; transform: translateY(-1px); }
            .auth-error-box {
              background: rgba(231,76,60,0.08);
              border: 1px solid rgba(231,76,60,0.3);
              border-radius: 8px;
              padding: 12px 14px;
              font-size: 13px;
              color: #e74c3c;
              margin-bottom: 16px;
              font-family: 'Outfit', sans-serif;
            }
            .auth-info-box {
              background: ${t.accentLight};
              border: 1px solid rgba(193,123,42,0.3);
              border-radius: 8px;
              padding: 12px 14px;
              font-size: 13px;
              color: ${t.accent};
              margin-bottom: 16px;
              font-family: 'Outfit', sans-serif;
            }
            .auth-link {
              color: ${t.accent};
              font-weight: 600;
              text-decoration: none;
              transition: color 0.2s;
            }
            .auth-divider {
              display: flex;
              align-items: center;
              gap: 12px;
              margin: 8px 0 16px;
            }
            .auth-divider-line {
              flex: 1;
              height: 1px;
              background: ${t.border};
            }
            .auth-divider-text {
              font-size: 12px;
              color: ${t.textMuted};
              font-family: 'Outfit', sans-serif;
              white-space: nowrap;
            }
            .auth-checkbox { accent-color: ${t.accent}; cursor: pointer; }
            .role-card {
              display: flex;
              flex-direction: column;
              gap: 4px;
              padding: 14px;
              border: 2px solid ${t.border};
              border-radius: 10px;
              cursor: pointer;
              transition: all 0.2s;
              background: ${t.bgCard};
            }
            .role-card:hover { border-color: ${t.accent}; }
            .role-card-active { border-color: ${t.accent} !important; background: ${t.accentLight} !important; }
            .role-label { font-size: 13px; font-weight: 600; color: ${t.text}; font-family: 'Outfit', sans-serif; }
            .role-sub   { font-size: 11px; color: ${t.textMuted}; font-family: 'Outfit', sans-serif; }
          `}</style>

          {/* Form content passed from child pages */}
          {children}
        </div>
      </div>
    </div>
  );
};

export default AuthLayout;
